<template>
    <div>
        <loader :is-visible="isLoading"></loader>
        <section class="main-content">
            <div ref="hellp" id="divMaindealData">
                <div class="row">
                    <div class="col-md-12 padding-t_8">
                        <div class="theme-primary partition-full">
                            <span class="p-name text-white">Skill Report</span>
                        </div>
                    </div>
                </div>
                <div class="border p-3">
                    <Form ref="JobPostForm">
                        <dynamic-form lang="en" ref="BarcodeReport" v-if="DataLoaded" :buttons="buttons" :schema="FormSchema" v-on:OnSubmit="onSubmit"></dynamic-form>
                    <div class="row placeholder">
                        <div class="col-md-12 p-0">
                            <ReportViewer v-if="parameter.length>0" :parameter="parameter" :reportPath="reportPath"></ReportViewer>
                        </div>
                    </div>
                    </Form>
                </div>
            </div>
        </section>
    </div>
    </template>
    
    <script>
    import '@boldreports/javascript-reporting-controls/Scripts/bold.report-designer.min';
    import '@boldreports/javascript-reporting-controls/Scripts/bold.report-viewer.min';
    import '@boldreports/javascript-reporting-controls/Scripts/data-visualization/ej.bulletgraph.min';
    import '@boldreports/javascript-reporting-controls/Scripts/data-visualization/ej.chart.min';
    import DataServices from "../services/DataService";
    import ReportViewer from '../views/HrReport/ReportViewer.vue';
    export default {
        components: {
            ReportViewer
        },
        data() {
            return {
                isLoading: false,
                 reportPath: null,
                 parameter: [],
                 LocationId: 0,
                // FindalLocationArray: [],          
                FormSchema: [{
                        layoutType: "triple",
                        Data: [{
                                astype: "SelectField",
                                label: this.$t("Location"),
                                name: "Location",
                                value: "",
                                placeholder: "",
                                config: {
                                    options: [],
                                    onChange: this.BindShift
                                },
                                validationRules: {
                                    "required": true
                                }
                            },
                            {
                                astype: "MultiSelectField",
                                label: this.$t("Users"),
                                name: "Users",
                                value: "",
                                placeholder: this.$t('Select') + " " + this.$t('Users'),
                                mode: "tag",
                                config: {
                                    options: [],
                                },
                            },
                            {
                                astype: "MultiSelectField",
                                label: this.$t("Shift"),
                                name: "Shift",
                                value: "",
                                placeholder: this.$t('Select') + " " + this.$t('Shift'),
                                mode: "tag",
                                config: {
                                    options: [],
                                  
                                },
                            },
                        ],
                    },
                    {
                        layoutType: "triple",
                        Data: [
                           {
                                astype: "MultiSelectField",
                                label: this.$t("Department"),
                                name: "Department",
                                value: "",
                                placeholder: this.$t('Select') + " " + this.$t('Department'),
                                mode: "tag",
                                config: {
                                    options: [],
                                    // onChange: this.onChangeDropdown,
                                    // onRemove: this.removeRecord,
                                },
                            },
                            {
                                astype: "MultiSelectField",
                                label: this.$t("Designation"),
                                name: "Designation",
                                value: "",
                                placeholder: this.$t('Select') + " " + this.$t('Designation'),
                                mode: "tag",
                                config: {
                                    options: [],
                                    // onChange: this.onChangeDropdown,
                                    // onRemove: this.removeRecord,
                                },
                            },
                            
                        ],
                    },
                ],
                buttons: [{
                        type: "submit",
                        class: "btn btn-success",
                        text: "<i class='fa fa-search pr-2'></i>Search",
                    },
                    {
                        type: "button",
                        class: "btn btn-danger",
                        text: "<i class='fa fa-close pr-2'></i>Clear all",
                        onClick: this.ClearAll
                    },
                ],
                DataLoaded: 0,
            };
        },
        created: async function () {
            debugger
            var vm = this;
            vm.userId = vm.GetUserInfo.ID;
            vm.companyId = vm.GetUserInfo.CompanyId;
            vm.UserType = vm.GetUserInfo.UserType;
            vm.DataLoaded = 1;
            await vm.ShowLocation();
            await vm.BindShift();
            await vm.GetUsers();
            await vm.BindDepartment();
            await vm.BindDesignation();
        },
        methods: {
    
            ClearAll: function () {
                var vm = this;
                (vm.FormSchema)[0].Data[0].value = '';
                (vm.FormSchema)[0].Data[1].value = '';
                (vm.FormSchema)[0].Data[2].value = '';
                (vm.FormSchema)[0].Data[3].value = '';
                (vm.FormSchema)[1].Data[0].value = '';
                (vm.FormSchema)[1].Data[1].value = '';
                (vm.FormSchema)[1].Data[2].value = '';
                // vm.parameter = [];
            },
    
            onSubmit(e) {
                var reportviewerObj = $("#viewer").data("boldReportViewer");
                if(reportviewerObj != null)
                {
                    reportviewerObj.destroy();
                }
                var vm = this;
                vm.isLoading=true;
                vm.reportPath = '';      
                vm.parameter=[];
                let myObj = {
                    reportName: "hruserskillreport",
                    locationId: e.Location,
                    shiftIds:  e.Shift.length > 0 ? e.Shift.map(item => item.value).join(",") : '',
                    DepartmentIds:  e.Department.length > 0 ? e.Department.map(item => item.value).join(",") : '',
                    DesignationIds:  e.Designation.length > 0 ? e.Designation.map(item => item.value).join(",") : '',
                    userIds:  e.Users.length > 0 ? e.Users.map(item => item.value).join(",") : '',
                }
                var postString = JSON.stringify(myObj);   
                 DataServices.ReportMain(postString).then(function (response) {
                    debugger;
                    vm.reportPath = response.data.reportpath;
                    vm.parameter = response.data.parameters;
                })
                vm.isLoading=false;
            },
            ShowLocation: async function () {
                debugger;
                var vm = this;
                await DataServices.GetCompanyLocation().then((response) => {
                    debugger;
                    if (response.data.length > 0) {
                        var LocationData = response.data;
                        LocationData.forEach(element => {
                            var Obj = {
                                name: element.LOCATION_NAME,
                                value: element.COMPANY_LOCATION_ID
                            }
                            vm.FormSchema[0].Data[0].config.options.push(Obj);
                        });  
                        vm.$refs.BarcodeReport.UpdateKeyValue();
                    }
                });
            },
    
            GetUsers: async function () {
                debugger;
                var vm = this;
                if(vm.UserType == 'CA'){
                    var url = `companyId=${vm.companyId}&locationId=0&moduleName=HRReport`
                await DataServices.GetUserListByLocationId(url).then((response) => {
                    debugger;
                    if (response.data.length > 0) {
                        var LocationData = response.data;
                        LocationData.forEach(element => {
                            var Obj = {
                                name: element.USER_NAME,
                                value: element.USER_ID
                            }
                            vm.FormSchema[0].Data[1].config.options.push(Obj);
                        });  
                        vm.$refs.BarcodeReport.UpdateKeyValue();
                    }
                });
                }
                else {
                    var url = `moduleName=HRReport`
                await DataServices.GetUserListByManagerId(url).then((response) => {
                    debugger;
                    if (response.data.length > 0) {
                        var LocationData = response.data;
                        LocationData.forEach(element => {
                            var Obj = {
                                name: element.USER_NAME,
                                value: element.USER_ID
                            }
                            vm.FormSchema[0].Data[1].config.options.push(Obj);
                        });  
                        vm.$refs.BarcodeReport.UpdateKeyValue();
                    }
                });
                }
            },

            BindShift: async function (x,y,z) {
                var vm = this;
                vm.LocationId = y == undefined ? 0 : y.value ;
                var url = `id=&moduleName=Hiring&type=USER_SHIFT_WITH_LOCATION_ID&search=&refId=${vm.LocationId}`;
                await DataServices.GetDDLData(url).then((response) => {
                    if (response.data.DATA.length > 0) {
                        debugger;
                        var LocationData = response.data.DATA;
                        LocationData.forEach(element => {
                            var Obj = {
                                name: element.name,
                                value: element.value
                            }
                            vm.FormSchema[0].Data[2].config.options.push(Obj);
                        });  
                        vm.$refs.BarcodeReport.UpdateKeyValue();
                    }
                });
            },

            BindDepartment: async function () {
                var vm = this;
                var url = `id=&moduleName=HIRINGReport&type=DEPARTMENT&search=&refId`;
                await DataServices.GetDDLData(url).then((response) => {
                    if (response.data.DATA.length > 0) {
                        var DepartmentData = response.data.DATA;
                        DepartmentData.forEach(element => {
                            var Obj = {
                                name: element.name,
                                value: element.value
                            }+
                            vm.FormSchema[1].Data[1].config.options.push(Obj);
                        });  
                        vm.$refs.BarcodeReport.UpdateKeyValue();
                    }
                });
            },

            BindDesignation: async function () {
                var vm = this;
                var url = `id=&moduleName=HIRINGReport&type=USER_DESIGNATION&search=&refId`;
                await DataServices.GetDDLData(url).then((response) => {
                    if (response.data.DATA.length > 0) {
                        var DepartmentData = response.data.DATA;
                        DepartmentData.forEach(element => {
                            var Obj = {
                                name: element.name,
                                value: element.value
                            }
                            vm.FormSchema[1].Data[2].config.options.push(Obj);
                        });  
                        vm.$refs.BarcodeReport.UpdateKeyValue();
                    }
                });
            },
        }
    };
    </script>
    